#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10,M=2e6+10;

struct Node{
    int son[26],fail;
}tr[M];

int n,q,tot,dfn[M],f[M][22],dep[M],num,idx[N],sz[M],c[M],tmp[M<<1],cnt;
char s[M];
vector<int> g[M];

int Insert(char s[]){
    int p=0;
    for(int i=0;s[i];i++){
        if(!tr[p].son[s[i]-'a'])
            tr[p].son[s[i]-'a']=++tot;
        p=tr[p].son[s[i]-'a'];
    }
    return p;
}

void bfs(){
    queue<int> q;
    for(int i=0;i<26;i++)
        if(tr[0].son[i])
            q.push(tr[0].son[i]);
    while(q.size()){
        int x=q.front();
        q.pop();
        g[tr[x].fail].push_back(x);
        for(int i=0;i<26;i++)
            if(!tr[x].son[i])
                tr[x].son[i]=tr[tr[x].fail].son[i];
            else
                tr[tr[x].son[i]].fail=tr[tr[x].fail].son[i],q.push(tr[x].son[i]);
    }
}

void dfs(int x){
    dfn[x]=++num,sz[x]=1;
    for(int y:g[x]){
        dep[y]=dep[x]+1;
        f[y][0]=x;
        for(int i=1;(1<<i)<=dep[y];i++)
            f[y][i]=f[f[y][i-1]][i-1];
        dfs(y);
        sz[x]+=sz[y];
    }
}

int LCA(int x,int y){
    if(dep[x]<dep[y])
        swap(x,y);
    for(int i=21;i>=0;i--)
        if(dep[f[x][i]]>=dep[y])
            x=f[x][i];
    if(x==y)
        return x;
    for(int i=21;i>=0;i--)
        if(f[x][i]!=f[y][i])
            x=f[x][i],y=f[y][i];
    return f[x][0];
}

bool cmp(int x,int y){
    return dfn[x]<dfn[y];
}

void add(int x,int k){
    for(;x<=tot+1;x+=(x&(-x)))
        c[x]+=k;
}

int ask(int x){
    int res=0;
    for(;x;x-=(x&(-x)))
        res+=c[x];
    return res;
}

void Query(char s[]){
    int p=0;
    cnt=0;
    for(int i=0;s[i];i++){
        p=tr[p].son[s[i]-'a'];
        tmp[++cnt]=p;
        add(dfn[p],1);
    }
    sort(tmp+1,tmp+cnt+1,cmp);
    for(int i=1;i<cnt;i++)
        add(dfn[LCA(tmp[i],tmp[i+1])],-1);
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%s",s);
        idx[i]=Insert(s);
    }
    bfs();
    dfs(0);
    scanf("%d",&q);
    while(q--){
        int op;
        scanf("%d",&op);
        if(op==1){
            scanf("%s",s);
            Query(s);
        }else{
            int x;
            scanf("%d",&x);
            printf("%d\n",ask(dfn[idx[x]]+sz[idx[x]]-1)-ask(dfn[idx[x]]-1));
        }
    }
    return 0;
}
